import{_ as t,o as i,c as s,ag as a}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"Fonctionnalites IA","description":"","frontmatter":{},"headers":[],"relativePath":"fr/advanced/ai-features.md","filePath":"fr/advanced/ai-features.md"}'),n={name:"fr/advanced/ai-features.md"};function o(r,e,l,u,d,c){return i(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="fonctionnalites-ia" tabindex="-1">Fonctionnalites IA <a class="header-anchor" href="#fonctionnalites-ia" aria-label="Permalink to &quot;Fonctionnalites IA&quot;">​</a></h1><p>MyCompanyDesk integre des fonctionnalites alimentees par l&#39;IA pour vous aider a travailler plus vite et plus intelligemment.</p><h2 id="guide-contextuel" tabindex="-1">Guide contextuel <a class="header-anchor" href="#guide-contextuel" aria-label="Permalink to &quot;Guide contextuel&quot;">​</a></h2><p>L&#39;assistant integre vous aide a naviguer dans MyCompanyDesk :</p><ul><li>Cliquez sur l&#39;<strong>icone d&#39;aide</strong> sur n&#39;importe quelle page pour une aide adaptee au contexte</li><li>Posez des questions sur les fonctionnalites, les flux de travail ou les parametres</li><li>Obtenez des instructions etape par etape pour les taches courantes</li><li>Disponible dans les quatre langues prises en charge</li></ul><p>Le guide comprend sur quelle page vous vous trouvez et fournit des suggestions pertinentes.</p><h3 id="limites-de-conversation" tabindex="-1">Limites de conversation <a class="header-anchor" href="#limites-de-conversation" aria-label="Permalink to &quot;Limites de conversation&quot;">​</a></h3><p>L&#39;utilisation du chat depend de votre plan :</p><table tabindex="0"><thead><tr><th>Plan</th><th>Messages de chat</th></tr></thead><tbody><tr><td>Gratuit</td><td>Limite</td></tr><tr><td>Pro</td><td>Allocation genereuse</td></tr><tr><td>Business</td><td>Allocation maximale</td></tr></tbody></table><h2 id="suggestions-ia" tabindex="-1">Suggestions IA <a class="header-anchor" href="#suggestions-ia" aria-label="Permalink to &quot;Suggestions IA&quot;">​</a></h2><p>Des recommandations intelligentes qui vous aident a categoriser et decrire vos enregistrements :</p><h3 id="categorisation-des-depenses" tabindex="-1">Categorisation des depenses <a class="header-anchor" href="#categorisation-des-depenses" aria-label="Permalink to &quot;Categorisation des depenses&quot;">​</a></h3><p>Lorsque vous creez une depense, l&#39;IA analyse la description et suggere la categorie la plus appropriee. Cela fait gagner du temps et assure une categorisation coherente.</p><h3 id="amelioration-des-descriptions" tabindex="-1">Amelioration des descriptions <a class="header-anchor" href="#amelioration-des-descriptions" aria-label="Permalink to &quot;Amelioration des descriptions&quot;">​</a></h3><p>L&#39;IA peut suggerer des descriptions plus claires et plus professionnelles pour :</p><ul><li>Les lignes de facturation</li><li>Les descriptions de depenses</li><li>Les notes clients</li></ul><h3 id="comment-ca-fonctionne" tabindex="-1">Comment ca fonctionne <a class="header-anchor" href="#comment-ca-fonctionne" aria-label="Permalink to &quot;Comment ca fonctionne&quot;">​</a></h3><ol><li>Creez ou modifiez un enregistrement</li><li>Recherchez l&#39;indicateur de suggestion IA</li><li>Examinez la suggestion</li><li>Cliquez sur <strong>Appliquer</strong> pour l&#39;utiliser, ou <strong>Ignorer</strong> pour passer</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Les suggestions IA necessitent le plan <strong>Pro</strong> ou superieur. Activez-les dans <strong>Entreprise &gt; Fonctionnalites</strong>.</p></div><h2 id="numerisation-de-recus" tabindex="-1">Numerisation de recus <a class="header-anchor" href="#numerisation-de-recus" aria-label="Permalink to &quot;Numerisation de recus&quot;">​</a></h2><p>L&#39;OCR alimente par l&#39;IA extrait les donnees des images de recus et des PDF :</p><ul><li><strong>Date</strong> -- Quand l&#39;achat a ete effectue</li><li><strong>Montant</strong> -- Cout total</li><li><strong>Fournisseur</strong> -- A qui vous avez paye</li><li><strong>Description</strong> -- Ce qui a ete achete</li></ul><p>Consultez <a href="/fr/advanced/receipt-scanning">Numerisation de recus</a> pour des instructions detaillees.</p><h2 id="verification-de-texte" tabindex="-1">Verification de texte <a class="header-anchor" href="#verification-de-texte" aria-label="Permalink to &quot;Verification de texte&quot;">​</a></h2><p>Verification de la grammaire et de l&#39;orthographe pour vos documents :</p><ul><li>Verifiez les descriptions de factures avant l&#39;envoi</li><li>Verifiez le contenu des devis</li><li>Corrigez les fautes de frappe dans les textes destines aux clients</li></ul><p>Prend en charge l&#39;anglais, le neerlandais, l&#39;allemand et le francais.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>La verification de texte necessite le plan <strong>Pro</strong> ou superieur.</p></div><h2 id="resumes-de-compte" tabindex="-1">Resumes de compte <a class="header-anchor" href="#resumes-de-compte" aria-label="Permalink to &quot;Resumes de compte&quot;">​</a></h2><p>L&#39;IA genere des resumes periodiques de votre activite commerciale :</p><ul><li><strong>Quotidien</strong> -- Apercu rapide des transactions du jour</li><li><strong>Hebdomadaire</strong> -- Bilan de la semaine avec tendances</li><li><strong>Mensuel</strong> -- Analyse mensuelle complete</li></ul><p>Les resumes sont generes dans votre langue preferee et disponibles depuis le tableau de bord.</p><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Activez les suggestions IA une fois et elles fonctionnent automatiquement en arriere-plan</li><li>La numerisation de recus est particulierement utile pour les recus papier -- prenez simplement une photo</li><li>Le guide contextuel peut repondre a la plupart des questions &quot;comment faire...&quot; concernant l&#39;application</li><li>Les fonctionnalites IA utilisent un traitement respectueux de la vie privee -- vos donnees restent securisees</li></ul>',34)])])}const g=t(n,[["render",o]]);export{m as __pageData,g as default};
